SET last_question = #{lastQuestion,jdbcType=VARCHAR},
    transfer_suggested = CASE WHEN #{transferSuggested} = 1 THEN 1 ELSE 0 END,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

